```javascript
function solve(nums) {
    const m = nums.length;
    const sieve = new Array(m).fill(true);
    sieve[0] = sieve[1] = false;
    for (let i = 2; i * i < m; i++) {
        if (sieve[i]) {
            for (let j = i * i; j < m; j += i) {
                sieve[j] = false;
            }
        }
    }
    let sumA = 0, sumB = 0;
    for (let i = 0; i < m; i++) {
        if (sieve[i]) {
            sumA += nums[i];
        } else {
            sumB += nums[i];
        }
    }
    return Math.abs(sumA - sumB);
}
```

